class Solution:
    def largestPalindrome(self, n: int, k: int) -> str:
        if n == 1:
            return str(max(i for i in range(1, 10) if i % k == 0))
        half_len = (n + 1) // 2
        start = 10 ** half_len - 1
        for left in range(start, 0, -1):
            left_str = str(left)
            if n % 2 == 0:
                candidate_str = left_str + left_str[::-1]
            else:
                candidate_str = left_str + left_str[:-1][::-1]
            candidate = int(candidate_str)
            if candidate % k == 0:
                return candidate_str
        return ""
```
